import { withSupabaseHandler } from "../../utils/withSupabaseHandler.ts";
import { setGameState } from "../../../../../lib/games/set_game_state.js";

export default withSupabaseHandler(async (req, supabase) => {
  try {
    // Parse JSON body
    const { gameId, new_state } = await req.json();

    if (!gameId || !new_state) {
      return new Response(
        JSON.stringify({ error: "Missing gameId or new_state" }),
        { status: 400 }
      );
    }

    // Update game state
    await setGameState(supabase, gameId, new_state);

    return new Response(JSON.stringify({ success: true }), { status: 200 });
  } catch (error) {
    return new Response(JSON.stringify({ error: error.message }), {
      status: 400,
    });
  }
});